DROP TABLE IF EXISTS migration_primary_keys;
DROP TABLE IF EXISTS migration_foreign_keys;

CREATE TABLE migration_primary_keys (
    module_name       VARCHAR(100) NOT NULL,
    table_name        VARCHAR(128) NOT NULL,
    column_name       VARCHAR(128) NOT NULL,
    constraint_name   VARCHAR(128) NOT NULL
);

CREATE TABLE migration_foreign_keys (
    module_name       VARCHAR(100) NOT NULL,
    child_table       VARCHAR(128) NOT NULL,
    child_column      VARCHAR(128) NOT NULL,
    parent_table      VARCHAR(128) NOT NULL,
    parent_column     VARCHAR(128) NOT NULL,
    fk_name           VARCHAR(128),
    pk_name           VARCHAR(128),
    position_no       INTEGER
);

CREATE INDEX idx_pk_table ON migration_primary_keys(table_name);
CREATE INDEX idx_fk_child ON migration_foreign_keys(child_table);
CREATE INDEX idx_fk_parent ON migration_foreign_keys(parent_table);

